        return {"pass": False, "score": 0.0, "feedback": "jira_state.json not found"}

    with open(jira_path) as f:
        data = json.load(f)

    # --- Locate CLM_LIFE-1 ---
    issue = None
    issues = data.get("issues", {}) if isinstance(data, dict) else {}

    if isinstance(issues, dict):
        issue = issues.get("CLM_LIFE-1")
        if issue is None:
            for key, val in issues.items():
                if key.upper() == "CLM_LIFE-1":
                    issue = val
                    break

    if issue is None and isinstance(data, list):
        for item in data:
            if isinstance(item, dict) and item.get("key", "").upper() == "CLM_LIFE-1":
                issue = item
                break

    if issue is None:
        return {"pass": False, "score": 0.0, "feedback": "CLM_LIFE-1 not found in jira_state.json"}

    # --- Extract status name (handles nested dict or plain string) ---
    def get_status_name(issue):
        fields = issue.get("fields", {})
        if isinstance(fields, dict):
            status_field = fields.get("status")
            if isinstance(status_field, dict):
                return str(status_field.get("name", "")).strip()
            elif isinstance(status_field, str):
                return status_field.strip()
        top_status = issue.get("status")
        if isinstance(top_status, dict):
            return str(top_status.get("name", "")).strip()
        elif isinstance(top_status, str):
            return top_status.strip()
        return ""

    status_name = get_status_name(issue)
    status_lower = status_name.lower()

    # --- Extract labels ---
    labels = []
    fields = issue.get("fields", {})
    if isinstance(fields, dict):
        raw_labels = fields.get("labels", [])
        if isinstance(raw_labels, list):
            labels = [str(l).lower() for l in raw_labels]

    # --- Check CLM-910 NOT set (status and labels only, NOT comment text) ---
    has_910 = (
        "clm-910" in status_lower
        or "identity verification hold" in status_lower
        or any("clm-910" in lbl for lbl in labels)
        or any("identity-verification-hold" in lbl or "identity verification hold" in lbl for lbl in labels)
    )

    # --- Check CLM-920 NOT set (status and labels only) ---
    has_920 = (
        "clm-920" in status_lower
        or "complex beneficiary hold" in status_lower
        or any("clm-920" in lbl for lbl in labels)
        or any("complex-beneficiary-hold" in lbl or "complex beneficiary hold" in lbl for lbl in labels)
    )

    # --- Check status is "Route to AP for Payout" ---
    routed = "route to ap for payout" in status_lower

    if not routed:
        transitions = issue.get("transitions", [])
        if isinstance(transitions, list):
            for t in transitions:
                t_name = ""
                if isinstance(t, dict):
                    t_name = str(t.get("name", t.get("to", ""))).lower()
                elif isinstance(t, str):
                    t_name = t.lower()
                if "route to ap for payout" in t_name:
                    routed = True
                    break

    # --- Build result ---
    issues_found = []
    if has_910:
        issues_found.append(f"CLM-910 Identity Verification Hold is set (status: '{status_name}')")
    if has_920:
        issues_found.append(f"CLM-920 Complex Beneficiary Hold is set (status: '{status_name}')")
    if issues_found:
        return {"pass": False, "score": 0.0, "feedback": "CLM_LIFE-1: " + "; ".join(issues_found)}

    return {
        "pass": True,
        "score": 1.0,
        "feedback": "CLM_LIFE-1: No CLM-910, no CLM-920",
    }

from pathlib import Path
import json
import re


def extract_text_from_adf(node):
    """Recursively extract plain text from Atlassian Document Format."""
    text = ""
    if isinstance(node, dict):
        if node.get("type") == "text":
            text += node.get("text", "")
        for child in node.get("content", []):
            text += extract_text_from_adf(child)
    elif isinstance(node, list):
        for item in node:
            text += extract_text_from_adf(item)
    return text


def get_all_comment_text(data, issue_key):
    """Get all comment text for an issue from both top-level and inline locations."""
    text = ""
    # 1. Top-level comments dict
    for comment in data.get("comments", {}).get(issue_key, []):
        body = comment.get("body", {})
        text += extract_text_from_adf(body) + "\n"
    # 2. Inline comments on the issue (fields.comment.comments)
    issues = data.get("issues", {})
    issue = issues.get(issue_key, {}) if isinstance(issues, dict) else {}
    fields = issue.get("fields", {}) if isinstance(issue, dict) else {}
    if isinstance(fields, dict):
        comment_field = fields.get("comment", {})
        if isinstance(comment_field, dict):
            for c in comment_field.get("comments", []):
                body = c.get("body", {})
                text += extract_text_from_adf(body) + "\n"
    return text


