from pathlib import Path
import json
import re


def extract_text_from_adf(node):
    """Recursively extract plain text from Atlassian Document Format.

    Block-level nodes (paragraph, heading, list item, etc.) are separated with
    newlines, and hardBreak nodes emit a newline, so the per-line payout checks
    below see the same line boundaries the comment author intended (ADF
    otherwise drops them, collapsing the whole comment onto one line).
    """
    block_types = {"paragraph", "heading", "blockquote", "listItem",
                   "bulletList", "orderedList", "codeBlock", "rule", "tableRow"}
    text = ""
    if isinstance(node, dict):
        node_type = node.get("type")
        if node_type == "text":
            text += node.get("text", "")
        elif node_type == "hardBreak":
            text += "\n"
        for child in node.get("content", []):
            text += extract_text_from_adf(child)
        if node_type in block_types:
            text += "\n"
    elif isinstance(node, list):
        for item in node:
            text += extract_text_from_adf(item)
    return text


def get_all_comment_text(data, issue_key):
    """Get all comment text for an issue from both top-level and inline locations."""
    text = ""
    # Top-level comments keyed by issue
    for comment in data.get("comments", {}).get(issue_key, []):
        body = comment.get("body", {})
        if isinstance(body, str):
            text += body + "\n"
        else:
            text += extract_text_from_adf(body) + "\n"
    # Inline comments inside issues -> fields -> comment
    issues = data.get("issues", {})
    issue = issues.get(issue_key, {}) if isinstance(issues, dict) else {}
    fields = issue.get("fields", {})
    if isinstance(fields, dict):
        comment_field = fields.get("comment", {})
        if isinstance(comment_field, dict):
            for c in comment_field.get("comments", []):
                body = c.get("body", {})
                if isinstance(body, str):
                    text += body + "\n"
                else:
                    text += extract_text_from_adf(body) + "\n"
    return text


