    # alloc_block is already lower-cased, so name/exclusion tokens are compared as-is.
    exclusion_words = [
        "exclud", "not listed", "not included", "not receiving", "not eligible",
        "ineligible", "redistribut", "deceased", "predecease", "n/a",
        "not applicable", "not payable", "no payout", "no allocation",
    ]

    def receives_payout(first_name):
        for line in alloc_block.split("\n"):
            if first_name in line and "drummond" in line:
                has_exclusion = any(w in line for w in exclusion_words)
                has_nonzero_amount = bool(re.search(r"\$\s*[1-9][\d,]*", line))
