        failures.append("George T. Drummond (contingent) must NOT be included in allocation with a payout amount")
    if receives_payout("linda"):
        failures.append("Linda M. Drummond (deceased) must NOT be included in allocation with a payout amount")

    if failures:
        return {"pass": False, "score": 0.0, "feedback": "CLM_LIFE-3 issues: " + "; ".join(failures)}

    return {
        "pass": True,
        "score": 1.0,
        "feedback": (
